const LEVEL2A_BANK=[{"word":"avoid","level":2,"definition":"to stay away from something","example":"She walked around the mud to avoid getting her new shoes dirty.","imageKeyword":"stepping around"},{"word":"burst","level":2,"definition":"to break open suddenly","example":"The balloon burst with a loud pop when it hit the thorn.","imageKeyword":"balloon popping"},{"word":"bury","level":2,"definition":"to put something under the ground","example":"The squirrel likes to bury nuts in the yard for winter.","imageKeyword":"burying treasure"},{"word":"cheer","level":2,"definition":"to shout with happiness to show support","example":"The crowd began to cheer when the team scored the winning goal.","imageKeyword":"cheering crowd"},{"word":"choose","level":2,"definition":"to pick one thing from many","example":"You may choose any flavor of ice cream you want.","imageKeyword":"picking choice"},{"word":"claim","level":2,"definition":"to say something is yours or is true","example":"Both children claim the toy is theirs, so the teacher had to help.","imageKeyword":"claiming own"},{"word":"combine","level":2,"definition":"to mix or put things together","example":"If you combine blue and yellow paint, you get green.","imageKeyword":"mixing together"},{"word":"command","level":2,"definition":"to give an order that must be followed","example":"The dog trainer commanded the puppy to sit and stay.","imageKeyword":"giving order"},{"word":"consider","level":2,"definition":"to think carefully about something","example":"Please consider all the choices before you pick your answer.","imageKeyword":"thinking carefully"},{"word":"continue","level":2,"definition":"to keep going and not stop what you are doing","example":"The rain will continue all day, so bring your umbrella.","imageKeyword":"keep going"},{"word":"control","level":2,"definition":"to have power over something and make it do what you want","example":"Use the remote to control which channel the TV shows.","imageKeyword":"remote control"},{"word":"cover","level":2,"definition":"to place something on top of another thing to hide or protect it","example":"Please cover the food, so the flies don't land on it.","imageKeyword":"covering lid"},{"word":"cross","level":2,"definition":"to go from one side to the other side of a road, river, or area","example":"Look both ways before you cross the street.","imageKeyword":"crossing street"},{"word":"crush","level":2,"definition":"to press something so hard it breaks into pieces","example":"The giant rock fell and crushed the empty box flat.","imageKeyword":"crushing flat"},{"word":"dare","level":2,"definition":"to be brave enough to try something scary","example":"Nobody dared to open the creaky old door in the basement.","imageKeyword":"brave dare"},{"word":"demand","level":2,"definition":"to ask for something in a strong, firm way","example":"The hungry baby demanded more food by banging on the table.","imageKeyword":"demanding firmly"},{"word":"develop","level":2,"definition":"to grow or change over time","example":"A tiny seed can develop into a tall sunflower in just a few weeks.","imageKeyword":"seedling growing stages"},{"word":"direct","level":2,"definition":"to show people or vehicles where they must go","example":"A crossing guard can direct cars to stop so children walk safely.","imageKeyword":"directing traffic"},{"word":"examine","level":2,"definition":"to look at something very closely","example":"The doctor examined my sore throat with a tiny flashlight.","imageKeyword":"examining closely"},{"word":"exchange","level":2,"definition":"to trade one thing for another","example":"The two friends exchanged stickers during lunch.","imageKeyword":"trading swap"},{"word":"excite","level":2,"definition":"to make someone feel very happy and full of life","example":"The news about the field trip excited all the students.","imageKeyword":"excited jumping"},{"word":"expect","level":2,"definition":"to think something will happen","example":"I expect the bus will come soon because it is almost eight o'clock.","imageKeyword":"waiting expecting"},{"word":"explore","level":2,"definition":"to look around a new place to learn about it","example":"We explored the cave with flashlights and found cool rocks inside.","imageKeyword":"exploring cave"},{"word":"express","level":2,"definition":"to show how you feel using words or actions","example":"She expressed her happiness by giving everyone a big smile.","imageKeyword":"expressing feelings"},{"word":"fail","level":2,"definition":"to not be able to do something you tried","example":"He failed to catch the ball, but he tried again and caught the next one.","imageKeyword":"missing fail"},{"word":"flow","level":2,"definition":"to move smoothly like water","example":"The river flows quickly over the rocks and down the hill.","imageKeyword":"flowing river"},{"word":"form","level":2,"definition":"to make or shape something into a new thing","example":"We used clay to form little animals for our art project.","imageKeyword":"shaping clay"},{"word":"gaze","level":2,"definition":"to look at something quietly with wonder or interest","example":"He gazed at the stars, amazed by how many there were.","imageKeyword":"gazing stars"},{"word":"guide","level":2,"definition":"to lead someone by going with them and showing the path","example":"The park ranger will guide us along the trail through the forest.","imageKeyword":"guide path"},{"word":"hasten","level":2,"definition":"to move or do something faster","example":"We hastened our steps when we saw the dark clouds coming.","imageKeyword":"hurrying fast"},{"word":"hide","level":2,"definition":"to put yourself or something where no one can see","example":"The children love to hide behind the big tree during the game.","imageKeyword":"hiding behind"},{"word":"hike","level":2,"definition":"to take a long walk outdoors, usually on a trail","example":"Our family likes to hike up the mountain every summer.","imageKeyword":"hiking trail"},{"word":"hug","level":2,"definition":"to put your arms around someone to show love","example":"She ran to hug her grandmother as soon as she walked in the door.","imageKeyword":"hugging people"},{"word":"hunt","level":2,"definition":"to chase or search for animals or things you want to catch","example":"The owl hunts for mice at night when it is very dark.","imageKeyword":"owl hunting"},{"word":"increase","level":2,"definition":"to make something bigger in size or amount","example":"The number of students in our class increased from twenty to twenty-five.","imageKeyword":"arrow going up"},{"word":"insist","level":2,"definition":"to say something strongly and not change your mind","example":"Mom insisted that we wear our coats because it was freezing outside.","imageKeyword":"firm insisting"},{"word":"instruct","level":2,"definition":"to teach someone by explaining the steps","example":"The coach instructed the players to pass the ball more often.","imageKeyword":"teaching instructing"},{"word":"admire","level":2,"definition":"to look at something and think it is very good","example":"Everyone stopped to admire the beautiful painting on the wall.","imageKeyword":"admiring art"},{"word":"announce","level":2,"definition":"to tell everyone something important","example":"The principal announced that school would end early because of the snow.","imageKeyword":"announcing news"},{"word":"approve","level":2,"definition":"to say yes or agree that something is all right","example":"Mom approved my plan to have a sleepover this weekend.","imageKeyword":"green checkmark approval"},{"word":"argue","level":2,"definition":"to disagree with someone using words","example":"The two brothers argued about whose turn it was to play the game.","imageKeyword":"arguing disagree"},{"word":"behave","level":2,"definition":"to act in a good or right way","example":"The teacher asked the class to behave nicely during the trip.","imageKeyword":"good behavior"},{"word":"celebrate","level":2,"definition":"to do something special because of a happy event","example":"We celebrated grandma's birthday with cake and balloons.","imageKeyword":"party celebrate"},{"word":"compare","level":2,"definition":"to look at two things to see how they are the same or different","example":"Let's compare these two shells to see which one is bigger.","imageKeyword":"side by side objects"},{"word":"convince","level":2,"definition":"to get someone to agree with you","example":"She convinced her dad to let them get a puppy by promising to walk it every day.","imageKeyword":"persuading talking"},{"word":"defend","level":2,"definition":"to protect someone or something from danger","example":"The father bird defended his nest by flapping his wings at the cat.","imageKeyword":"defending protecting"},{"word":"disappear","level":2,"definition":"to go away so no one can see it anymore","example":"The magician made the coin disappear right before our eyes.","imageKeyword":"vanishing magic"},{"word":"encourage","level":2,"definition":"to say kind words to help someone keep trying","example":"Her friends encouraged her to try again after she fell off the bike.","imageKeyword":"cheering support"},{"word":"improve","level":2,"definition":"to get better at something","example":"She improved her reading by practicing every night before bed.","imageKeyword":"getting better"},{"word":"interrupt","level":2,"definition":"to start talking when someone else is already speaking","example":"Please don't interrupt me while I am telling the story.","imageKeyword":"interrupting talking"},{"word":"observe","level":2,"definition":"to watch something carefully","example":"We observed the caterpillar as it slowly turned into a butterfly.","imageKeyword":"watching carefully"},{"word":"organize","level":2,"definition":"to put things in order so they are neat","example":"She organized her crayons by color in a neat row.","imageKeyword":"organizing neat"},{"word":"bold","level":2,"definition":"willing to take risks and do big things without fear","example":"The bold explorer walked into the dark cave without any fear.","imageKeyword":"bold explorer"},{"word":"brief","level":2,"definition":"taking very little time from start to finish","example":"The rain was brief—it stopped after just five minutes.","imageKeyword":"short quick"},{"word":"delicate","level":2,"definition":"easily broken or damaged; needing gentle care","example":"The delicate butterfly wing had tiny patterns you could barely see.","imageKeyword":"delicate butterfly"},{"word":"dense","level":2,"definition":"very close together with no space","example":"The forest was so dense that sunlight could barely get through the trees.","imageKeyword":"dense forest"},{"word":"dim","level":2,"definition":"having only a small amount of light; hard to see in","example":"The dim light in the hallway made it hard to find the door.","imageKeyword":"dim light"},{"word":"distant","level":2,"definition":"far away","example":"We could see the distant mountains, but it would take hours to reach them.","imageKeyword":"distant mountains"},{"word":"drowsy","level":2,"definition":"feeling very tired and ready to sleep","example":"The warm blanket made him drowsy, and he soon fell asleep.","imageKeyword":"sleepy drowsy"},{"word":"dusty","level":2,"definition":"covered with tiny bits of dirt","example":"The dusty old book hadn't been opened in many years.","imageKeyword":"dusty book"},{"word":"elegant","level":2,"definition":"beautiful and graceful in a fancy way","example":"The elegant swan glided smoothly across the lake.","imageKeyword":"elegant swan"},{"word":"faint","level":2,"definition":"very weak and hard to notice","example":"There was a faint smell of cookies coming from the kitchen far away.","imageKeyword":"faint fading"},{"word":"familiar","level":2,"definition":"something you have seen or know about before","example":"The song sounded familiar because he had heard it many times.","imageKeyword":"recognize familiar"},{"word":"flat","level":2,"definition":"smooth and level with no bumps","example":"The pancake was thin and flat like a plate.","imageKeyword":"flat pancake"},{"word":"flexible","level":2,"definition":"able to bend well without breaking","example":"The flexible rubber band stretched without snapping.","imageKeyword":"bending flexible"},{"word":"foggy","level":2,"definition":"filled with thick mist so you cannot see well","example":"The morning was so foggy that we couldn't see across the playground.","imageKeyword":"foggy morning"},{"word":"glossy","level":2,"definition":"smooth and shiny like glass","example":"The glossy paper from the store showed all the new toys.","imageKeyword":"glossy shiny"},{"word":"grim","level":2,"definition":"looking serious and gloomy","example":"The teacher had a grim face when she saw the mess in the classroom.","imageKeyword":"serious face"},{"word":"harsh","level":2,"definition":"unpleasantly severe or extreme","example":"The harsh winter wind stung their faces as they walked to school.","imageKeyword":"harsh wind"},{"word":"heavy","level":2,"definition":"weighing a lot and hard to lift","example":"The heavy backpack made her shoulders ache by the end of the day.","imageKeyword":"heavy backpack"},{"word":"helpless","level":2,"definition":"weak and unable to do anything on your own","example":"The helpless baby bird sat in the nest waiting for its mother.","imageKeyword":"baby bird helpless"},{"word":"humble","level":2,"definition":"quiet about your own skills; letting actions speak instead of bragging","example":"Even though he won first place, he was humble and thanked his team.","imageKeyword":"humble modest"},{"word":"innocent","level":2,"definition":"having done nothing wrong; free of blame","example":"The puppy looked innocent, but it was the one who chewed the shoe.","imageKeyword":"innocent puppy"},{"word":"invisible","level":2,"definition":"not able to be seen","example":"The glass door was so clean it was almost invisible.","imageKeyword":"invisible glass"},{"word":"keen","level":2,"definition":"very interested and eager to do something","example":"He was keen to start reading the new book he got for his birthday.","imageKeyword":"eager keen"},{"word":"lean","level":2,"definition":"thin and fit","example":"The lean runner finished the race first because she was fast and fit.","imageKeyword":"lean runner"},{"word":"lively","level":2,"definition":"full of life and fun","example":"The lively puppy bounced around the yard chasing butterflies.","imageKeyword":"lively puppy"},{"word":"lovely","level":2,"definition":"very pretty or nice","example":"What a lovely garden full of colorful flowers and green plants!","imageKeyword":"lovely garden"},{"word":"magnificent","level":2,"definition":"grand and strikingly beautiful, suggesting splendor","example":"The magnificent fireworks lit up the whole night sky.","imageKeyword":"magnificent fireworks"},{"word":"moist","level":2,"definition":"slightly wet, often in a soft or good way","example":"The moist soil was perfect for planting seeds in the garden.","imageKeyword":"moist soil"},{"word":"neat","level":2,"definition":"clean and in good order","example":"Her desk was always neat with pencils lined up in a row.","imageKeyword":"neat desk"},{"word":"noble","level":2,"definition":"good, brave, and fair","example":"The noble knight promised to help everyone in the village.","imageKeyword":"noble knight"},{"word":"odd","level":2,"definition":"strange or unusual","example":"It was odd to see snow in April when it was supposed to be spring.","imageKeyword":"strange odd"},{"word":"pale","level":2,"definition":"light in color, not bright","example":"Her face turned pale when she heard the scary noise.","imageKeyword":"pale face"},{"word":"plump","level":2,"definition":"round and a little bit fat","example":"The plump blueberries were ready to pick from the bush.","imageKeyword":"plump berries"},{"word":"precious","level":2,"definition":"very special and valuable","example":"The ring was precious to him because it belonged to his grandfather.","imageKeyword":"precious gem"},{"word":"pure","level":2,"definition":"clean and not mixed with anything else","example":"The mountain stream had pure water that was clear as glass.","imageKeyword":"pure water"},{"word":"rare","level":2,"definition":"very hard to find because there are so few","example":"It is rare to see a bald eagle, so we were very lucky that day.","imageKeyword":"rare eagle"},{"word":"raw","level":2,"definition":"not cooked or changed from its natural state","example":"You should not eat raw chicken because it can make you sick.","imageKeyword":"raw vegetables"},{"word":"round","level":2,"definition":"shaped like a circle or ball","example":"The round orange rolled off the table and onto the floor.","imageKeyword":"round ball"},{"word":"rude","level":2,"definition":"saying or doing mean things that hurt people's feelings","example":"It is rude to talk while someone else is speaking.","imageKeyword":"rude interrupting"},{"word":"rusty","level":2,"definition":"covered in a rough, dark brown layer that forms when metal gets wet","example":"The rusty old bike had been left in the rain for too long.","imageKeyword":"rusty bike"},{"word":"scarce","level":2,"definition":"hard to find because there is not enough for everyone who needs it","example":"When a trading card is scarce, collectors will pay a much higher price for it.","imageKeyword":"scarce rare item"},{"word":"slender","level":2,"definition":"thin and graceful","example":"The slender candle fit perfectly in the tiny holder.","imageKeyword":"slender candle"},{"word":"soft","level":2,"definition":"easy to press or squeeze; gentle to the touch, like a pillow","example":"The soft kitten fur felt like a cloud when she petted it.","imageKeyword":"soft kitten"},{"word":"abundant","level":2,"definition":"more than enough, a very large amount","example":"The store had abundant supplies, so prices stayed low all summer.","imageKeyword":"plenty abundant"},{"word":"absurd","level":2,"definition":"very silly or unreasonable","example":"The clown wore an absurd hat that was shaped like a giant banana.","imageKeyword":"silly absurd"},{"word":"accurate","level":2,"definition":"right and without mistakes","example":"Her drawing was so accurate it looked like a photograph.","imageKeyword":"accurate exact"},{"word":"brittle","level":2,"definition":"hard but easy to snap or break","example":"The brittle twig snapped in half when he stepped on it.","imageKeyword":"brittle breaking"},{"word":"colorful","level":2,"definition":"having many bright colors","example":"The colorful parrot had red, blue, and yellow feathers.","imageKeyword":"colorful parrot"},{"word":"cruel","level":2,"definition":"wanting to hurt others on purpose","example":"It is cruel to pull a cat's tail because it causes pain.","imageKeyword":"mean cruel"},{"word":"daring","level":2,"definition":"brave enough to do dangerous things","example":"The daring pilot flew through the storm to deliver medicine.","imageKeyword":"daring brave"},{"word":"filthy","level":2,"definition":"very dirty, covered all over in dirt","example":"His clothes were filthy after playing in the mud all afternoon.","imageKeyword":"filthy dirty"},{"word":"gorgeous","level":2,"definition":"very beautiful in a way that gets your attention","example":"The gorgeous sunset turned the sky orange and pink.","imageKeyword":"gorgeous sunset"},{"word":"horrible","level":2,"definition":"causing horror or intense discomfort; shockingly bad","example":"The horrible smell from the garbage made everyone hold their nose.","imageKeyword":"horrible smell"},{"word":"mysterious","level":2,"definition":"hard to explain or understand","example":"A mysterious light appeared in the forest at night.","imageKeyword":"mysterious light"},{"word":"pleasant","level":2,"definition":"nice and enjoyable","example":"The pleasant breeze cooled us down on the hot summer day.","imageKeyword":"pleasant breeze"},{"word":"powerful","level":2,"definition":"having great power","example":"The powerful wind blew the leaves off every tree on the street.","imageKeyword":"powerful wind"},{"word":"ridiculous","level":2,"definition":"so silly it makes you laugh","example":"The dog looked ridiculous wearing a tiny hat and sunglasses.","imageKeyword":"ridiculous funny"},{"word":"serious","level":2,"definition":"meaning what you say; focused and not joking around","example":"She had a serious look on her face when she told us the rules.","imageKeyword":"stern teacher face"},{"word":"spotless","level":2,"definition":"perfectly clean with no dirt at all","example":"After cleaning all day, the kitchen was spotless.","imageKeyword":"spotless clean"},{"word":"tremendous","level":2,"definition":"extremely large or powerful in a way that overwhelms","example":"The audience gave a tremendous cheer that shook the whole room.","imageKeyword":"tremendous big"},{"word":"visible","level":2,"definition":"able to be seen","example":"The lighthouse was visible from miles away because of its bright light.","imageKeyword":"visible lighthouse"},{"word":"weak","level":2,"definition":"having little strength or power","example":"The weak kitten could barely stand on its tiny legs.","imageKeyword":"weak small"},{"word":"wealthy","level":2,"definition":"having a lot of money","example":"The wealthy man built a library, so everyone could read for free.","imageKeyword":"wealthy rich"},{"word":"wicked","level":2,"definition":"very bad or evil","example":"The wicked witch in the story tried to trick the children.","imageKeyword":"wicked witch"},{"word":"worthless","level":2,"definition":"having no value at all","example":"The broken toy was worthless because none of the pieces worked.","imageKeyword":"broken toy pieces"},{"word":"briefly","level":2,"definition":"for a short time; using few words","example":"She briefly explained the rules, then we started the game.","imageKeyword":"quick summary"},{"word":"constantly","level":2,"definition":"without stopping; all the time without a break","example":"The puppy constantly wagged its tail because it was always happy.","imageKeyword":"always nonstop"},{"word":"continuously","level":2,"definition":"in one long stretch without any break at all","example":"The river flows continuously, never stopping day or night.","imageKeyword":"nonstop flowing"},{"word":"currently","level":2,"definition":"happening right now","example":"She is currently reading a book about dinosaurs.","imageKeyword":"right now"},{"word":"formerly","level":2,"definition":"in the past, before now","example":"The building was formerly a school, but now it is a library.","imageKeyword":"before past"},{"word":"instantly","level":2,"definition":"happening right away without any delay","example":"The light turned on instantly when she flipped the switch.","imageKeyword":"light switch on"},{"word":"mostly","level":2,"definition":"almost all, but not completely","example":"The jar was mostly empty—only a few candies were left.","imageKeyword":"almost all"},{"word":"nearly","level":2,"definition":"almost but not quite","example":"She nearly finished the race but tripped right before the finish line.","imageKeyword":"almost there"},{"word":"normally","level":2,"definition":"in the regular way, when nothing special changes","example":"We normally eat breakfast at seven, but today we slept late.","imageKeyword":"usual normal"},{"word":"originally","level":2,"definition":"at first, before things changed","example":"The house was originally painted white, but now it is blue.","imageKeyword":"first beginning"},{"word":"partly","level":2,"definition":"to some degree; only a piece of the whole, with more left over","example":"The sky was partly cloudy, so we could still see some blue.","imageKeyword":"partly half"},{"word":"possibly","level":2,"definition":"maybe, there is a chance it could happen","example":"It will possibly snow tonight, so keep your boots by the door.","imageKeyword":"maybe possible"},{"word":"presently","level":2,"definition":"soon; in a short while","example":"He is presently working on his art project in the other room.","imageKeyword":"now current"},{"word":"previously","level":2,"definition":"at an earlier time in the past, not recently","example":"He had previously visited the museum, so he knew where to find the dinosaur bones.","imageKeyword":"before earlier"},{"word":"probably","level":2,"definition":"very likely to happen","example":"It will probably rain because the sky is full of dark clouds.","imageKeyword":"likely rain clouds"},{"word":"promptly","level":2,"definition":"right on time or right away","example":"Class starts at nine, and the teacher arrives promptly every day.","imageKeyword":"on time"},{"word":"regularly","level":2,"definition":"happening at the same time again and again","example":"She regularly waters her plant every morning before school.","imageKeyword":"regular routine"},{"word":"shortly","level":2,"definition":"in a little while, very soon","example":"The movie will start shortly, so find your seat now.","imageKeyword":"soon shortly"},{"word":"simply","level":2,"definition":"without much work, nothing more","example":"You can fix it simply by pressing the restart button.","imageKeyword":"easy simple"},{"word":"sometimes","level":2,"definition":"now and then, not always","example":"Sometimes we walk to school, and sometimes we take the bus.","imageKeyword":"sometimes calendar"},{"word":"steadily","level":2,"definition":"in a smooth, even way without stopping","example":"The rain fell steadily all afternoon without getting worse or letting up.","imageKeyword":"steady even"},{"word":"still","level":2,"definition":"even now, continuing","example":"It is ten o'clock, and she is still reading her book.","imageKeyword":"still continuing"},{"word":"typically","level":2,"definition":"in the most common way for that kind of thing","example":"He typically walks to school, but today his mom drove him.","imageKeyword":"usually typical"},{"word":"usually","level":2,"definition":"more often than not","example":"We usually have pizza on Friday nights.","imageKeyword":"usual routine"},{"word":"simultaneously","level":2,"definition":"at the exact same moment, with two actions happening together","example":"The two friends jumped into the pool simultaneously and made a huge splash.","imageKeyword":"two clocks same time"},{"word":"initially","level":2,"definition":"at the very beginning, before anything changed","example":"She was initially scared of the water, but soon she loved swimming.","imageKeyword":"starting line race"},{"word":"permanently","level":2,"definition":"forever; in a way that lasts and never changes","example":"The marker stain permanently stayed on the shirt even after washing.","imageKeyword":"forever lasting"},{"word":"temporarily","level":2,"definition":"for a limited time, with plans to go back to usual later","example":"The road is temporarily closed while workers fix the broken pipe.","imageKeyword":"detour sign"},{"word":"lately","level":2,"definition":"during the past few days or weeks, very recently","example":"It has been very cold lately, so we wear extra layers.","imageKeyword":"recent week calendar"},{"word":"overnight","level":2,"definition":"during the night while you sleep","example":"The snow fell overnight, and everything was white in the morning.","imageKeyword":"nighttime overnight"},{"word":"yearly","level":2,"definition":"happening one time each year","example":"The town has a yearly parade every summer with music and floats.","imageKeyword":"annual yearly"},{"word":"hourly","level":2,"definition":"happening every hour","example":"The clock chimes hourly, so you hear it ring twelve times at noon.","imageKeyword":"every hour"},{"word":"illustration","level":2,"definition":"a picture in a book that shows what is happening","example":"The illustration showed a dragon flying over a mountain.","imageKeyword":"book illustration"},{"word":"diagram","level":2,"definition":"a drawing that shows how something works","example":"The diagram in our science book shows the parts of a flower.","imageKeyword":"diagram drawing"},{"word":"vocabulary","level":2,"definition":"all the words a person knows","example":"Reading every day helps you grow your vocabulary.","imageKeyword":"words vocabulary"},{"word":"definition","level":2,"definition":"what a word means","example":"Look up the definition in the dictionary if you don't know the word.","imageKeyword":"dictionary definition"},{"word":"fact","level":2,"definition":"something that is true and can be proven","example":"It is a fact that the Earth goes around the Sun.","imageKeyword":"fact true"},{"word":"summary","level":2,"definition":"a short telling of the most important parts","example":"Write a summary of the story in just three sentences.","imageKeyword":"short summary"},{"word":"topic","level":2,"definition":"what something is mainly about or the subject being talked about","example":"The topic of today's lesson is the water cycle.","imageKeyword":"topic subject"},{"word":"conclusion","level":2,"definition":"the end or final part","example":"At the conclusion of the movie, the hero saved the day.","imageKeyword":"ending conclusion"},{"word":"passage","level":2,"definition":"a short part of a book or story","example":"Read the passage on page five and answer the questions.","imageKeyword":"text passage"},{"word":"research","level":2,"definition":"looking for facts to learn about something","example":"We did research on penguins by reading three different books.","imageKeyword":"research books"},{"word":"method","level":2,"definition":"a way of doing something","example":"The teacher showed us a new method for solving math problems.","imageKeyword":"method way"},{"word":"experiment","level":2,"definition":"a test to find out what happens","example":"Our experiment showed that plants grow faster in sunlight.","imageKeyword":"science experiment"},{"word":"creature","level":2,"definition":"any living being, real or imagined","example":"We saw a strange creature with eight legs in the garden—it was a spider!","imageKeyword":"creature animal"},{"word":"moisture","level":2,"definition":"wetness; water you can feel on something or in the air","example":"There was moisture on the grass every morning from the cool night air.","imageKeyword":"dew moisture"},{"word":"material","level":2,"definition":"what something is made of, like cloth or metal","example":"The material of his jacket was soft and kept him very warm.","imageKeyword":"fabric material"},{"word":"source","level":2,"definition":"the place or thing where something first comes from","example":"The river's source is a small spring high up in the mountains.","imageKeyword":"source beginning"},{"word":"motion","level":2,"definition":"the act of moving or changing position","example":"The motion of the swing going back and forth made her laugh.","imageKeyword":"swinging motion"},{"word":"mixture","level":2,"definition":"two or more things stirred together","example":"The cake batter is a mixture of flour, eggs, and sugar.","imageKeyword":"mixing bowl"},{"word":"direction","level":2,"definition":"the way something is moving or pointing","example":"The wind changed direction and started blowing from the north.","imageKeyword":"arrow direction"},{"word":"shelter","level":2,"definition":"a basic or temporary place that protects you from weather or danger","example":"The hikers found shelter under a big rock when it started to rain.","imageKeyword":"shelter cover"},{"word":"predator","level":2,"definition":"an animal that hunts other animals for food","example":"The hawk is a predator that catches mice and small birds.","imageKeyword":"predator hawk"},{"word":"prey","level":2,"definition":"an animal that others hunt and eat","example":"The rabbit is prey for foxes, so it runs very fast to escape.","imageKeyword":"prey rabbit"},{"word":"oxygen","level":2,"definition":"a gas in the air that we breathe to stay alive","example":"Trees make oxygen, which is why forests help us breathe clean air.","imageKeyword":"oxygen breathing"},{"word":"galaxy","level":2,"definition":"a huge group of stars in space","example":"Our sun is just one star in a galaxy with billions of others.","imageKeyword":"galaxy stars"},{"word":"fossil","level":2,"definition":"the remains of a plant or animal from long ago, kept safe inside rock","example":"We found a fossil of a leaf that was millions of years old.","imageKeyword":"fossil rock"},{"word":"mineral","level":2,"definition":"a natural solid found in rocks or in the ground","example":"Gold is a mineral that people dig out of the earth.","imageKeyword":"mineral crystal"},{"word":"current","level":2,"definition":"a steady flow of water, air, or electricity moving in one direction; also means happening now","example":"The strong current in the river pushed the boat downstream.","imageKeyword":"river current"},{"word":"vapor","level":2,"definition":"water in the form of a gas, often seen as steam or mist","example":"Steam from the hot soup rose into the air as water vapor.","imageKeyword":"steam vapor"},{"word":"erosion","level":2,"definition":"the slow wearing away of rock or soil by wind or water","example":"Erosion from the river carved a deep valley over thousands of years.","imageKeyword":"erosion cliff"},{"word":"orbit","level":2,"definition":"the path something takes as it moves around another thing in space","example":"The Earth takes one year to complete its orbit around the Sun.","imageKeyword":"orbit planet"},{"word":"gravity","level":2,"definition":"the force that pulls things down toward the ground","example":"Gravity is what makes a ball fall back down after you throw it up.","imageKeyword":"falling gravity"},{"word":"species","level":2,"definition":"a group of living things that are the same kind","example":"There are many species of birds, from tiny hummingbirds to huge eagles.","imageKeyword":"species animals"},{"word":"community","level":2,"definition":"a group of people who live in the same area","example":"Our community worked together to build a new playground.","imageKeyword":"community people"},{"word":"population","level":2,"definition":"all the people living in one place","example":"The population of our town grew when new families moved in.","imageKeyword":"population town"},{"word":"culture","level":2,"definition":"the way of life of a group of people","example":"In their culture, families gather every Sunday for a big meal.","imageKeyword":"culture tradition"},{"word":"ancestor","level":2,"definition":"a family member who lived long before you","example":"Her ancestors came from a small village across the ocean.","imageKeyword":"ancestor family tree"},{"word":"generation","level":2,"definition":"all the people born around the same time","example":"Kids, parents, and grandparents are three different generations.","imageKeyword":"generation family"},{"word":"volunteer","level":2,"definition":"a person who helps without being paid","example":"Volunteers helped clean up the beach after the storm.","imageKeyword":"volunteer helping"},{"word":"merchant","level":2,"definition":"a person who buys and sells things","example":"The merchant at the market sold fresh fruits and vegetables.","imageKeyword":"merchant shop"},{"word":"pioneer","level":2,"definition":"one of the first people to go to a new place or try something new","example":"The pioneers traveled west in covered wagons to find new land.","imageKeyword":"pioneer wagon"},{"word":"president","level":2,"definition":"the leader of a country or group","example":"The president of the club welcomed all the new members.","imageKeyword":"president leader"},{"word":"profession","level":2,"definition":"a job that needs special training","example":"Being a doctor is a profession that requires many years of school.","imageKeyword":"profession job"},{"word":"companion","level":2,"definition":"a friend who goes with you","example":"The dog was her loyal companion on every walk through the woods.","imageKeyword":"companion friend"},{"word":"guardian","level":2,"definition":"a person who takes care of someone","example":"His guardian made sure he ate healthy food and went to bed on time.","imageKeyword":"guardian caretaker"},{"word":"immigrant","level":2,"definition":"a person who moves to a new country to live","example":"Many immigrants came to this country to find a better life.","imageKeyword":"immigrant new home"},{"word":"inspector","level":2,"definition":"a person whose job is to check that things are done right","example":"The inspector looked at the building to make sure it was safe.","imageKeyword":"inspector checking"},{"word":"messenger","level":2,"definition":"a person who carries news from one place to another","example":"The messenger rode his horse fast to deliver the important letter.","imageKeyword":"messenger delivering"},{"word":"relative","level":2,"definition":"a person in your family","example":"Every relative came to the big reunion at the park.","imageKeyword":"family relative"},{"word":"scholar","level":2,"definition":"a person who studies and learns a lot","example":"The scholar read hundreds of books about ancient history.","imageKeyword":"scholar studying"},{"word":"witness","level":2,"definition":"a person who sees something happen","example":"She was a witness to the accident and told the police what she saw.","imageKeyword":"witness seeing"},{"word":"advantage","level":2,"definition":"something that gives you a better chance to succeed","example":"Being tall is an advantage in basketball because you can reach the hoop.","imageKeyword":"advantage benefit"},{"word":"courage","level":2,"definition":"being brave when you are scared","example":"It took courage to stand up and speak in front of the whole school.","imageKeyword":"courage brave"},{"word":"effort","level":2,"definition":"trying hard to do something","example":"She put a lot of effort into her science project and won first place.","imageKeyword":"effort trying"},{"word":"knowledge","level":2,"definition":"things you know from learning","example":"Reading books gives you knowledge about the world.","imageKeyword":"knowledge books"},{"word":"patience","level":2,"definition":"being able to wait without getting upset","example":"It takes patience to grow a garden because plants need weeks to get big.","imageKeyword":"patience waiting"},{"word":"responsibility","level":2,"definition":"a job or duty that you must do","example":"Feeding the class pet is my responsibility this week.","imageKeyword":"responsibility duty"},{"word":"triumph","level":2,"definition":"a great win","example":"Our team's triumph in the championship game made the whole school cheer.","imageKeyword":"triumph victory"},{"word":"accident","level":2,"definition":"something bad that happens without being planned","example":"She spilled the milk by accident when her elbow bumped the glass.","imageKeyword":"accident spill"},{"word":"attitude","level":2,"definition":"the way you think and feel about something","example":"A positive attitude helps you keep trying even when things are hard.","imageKeyword":"attitude positive"},{"word":"boundary","level":2,"definition":"a line that shows where one area ends and another begins","example":"The fence is the boundary between our yard and the neighbor's yard.","imageKeyword":"boundary fence"},{"word":"consequence","level":2,"definition":"a result caused by something you did","example":"The consequence of forgetting her lunch was being hungry all afternoon.","imageKeyword":"consequence result"},{"word":"conversation","level":2,"definition":"a talk between two or more people","example":"They had a long conversation about their favorite books.","imageKeyword":"conversation talking"},{"word":"decision","level":2,"definition":"a choice you make after thinking","example":"Choosing which school to attend was a big decision for the family.","imageKeyword":"decision choice"},{"word":"evidence","level":2,"definition":"facts or signs that help prove something is true","example":"Muddy footprints were evidence that someone walked through the garden.","imageKeyword":"evidence clue"},{"word":"experience","level":2,"definition":"something you live through and remember","example":"Visiting the ocean for the first time was an amazing experience.","imageKeyword":"experience memory"},{"word":"imagination","level":2,"definition":"the part of your mind that makes up new ideas and pictures","example":"He used his imagination to pretend the cardboard box was a spaceship.","imageKeyword":"imagination creative"},{"word":"occasion","level":2,"definition":"a special time or event","example":"A birthday is a happy occasion for cake and presents.","imageKeyword":"occasion celebration"},{"word":"solution","level":2,"definition":"the answer to a problem","example":"Working together was the solution to finishing the project on time.","imageKeyword":"solution answer"},{"word":"inspect","level":2,"definition":"to look at something closely to check if it is correct or safe","example":"The teacher inspected our projects to make sure they were finished.","imageKeyword":"inspecting closely"},{"word":"select","level":2,"definition":"to choose something carefully","example":"Please select one book from the shelf to read this week.","imageKeyword":"selecting picking"},{"word":"supply","level":2,"definition":"to give or provide something that is needed","example":"The school asked the store to supply paper and pencils for every classroom.","imageKeyword":"delivery truck supplies"},{"word":"survive","level":2,"definition":"to stay alive through something dangerous or difficult","example":"The little plant survived the cold winter and bloomed in spring.","imageKeyword":"survive alive"},{"word":"transform","level":2,"definition":"to change completely into something different","example":"The caterpillar will transform into a beautiful butterfly.","imageKeyword":"transform change"},{"word":"transport","level":2,"definition":"to carry something from one place to another","example":"Trucks transport food from farms to grocery stores.","imageKeyword":"transport truck","pronunciationNote":"Here as verb: /trænsˈpɔːrt/. The noun form is /ˈtrænspɔːrt/. Audio may use noun pronunciation."},{"word":"identify","level":2,"definition":"to figure out what something is","example":"Can you identify which bird is singing by listening to its call?","imageKeyword":"identify recognize"},{"word":"inherit","level":2,"definition":"to receive something from a family member who has died, or to get traits passed down from parents","example":"She inherited her grandmother's blue eyes and curly hair.","imageKeyword":"inherit family"},{"word":"massive","level":2,"definition":"very large and heavy","example":"The massive boulder was too big for anyone to move.","imageKeyword":"massive rock"},{"word":"miniature","level":2,"definition":"much smaller than usual","example":"She built a miniature house for her dolls out of cardboard.","imageKeyword":"miniature tiny"},{"word":"obvious","level":2,"definition":"very easy to see or understand","example":"It was obvious the dog ate the cake because crumbs were all over its face.","imageKeyword":"obvious clear"},{"word":"ordinary","level":2,"definition":"plain and usual, just like everything else around it","example":"It seemed like an ordinary day until the surprise party started.","imageKeyword":"regular school day"},{"word":"particular","level":2,"definition":"one certain thing out of many, chosen for a special reason","example":"She wanted that particular book, not any of the other ones.","imageKeyword":"specific one"},{"word":"peculiar","level":2,"definition":"strange or odd in a way that catches your eye","example":"The peculiar noise coming from the closet sounded like a squeaky toy.","imageKeyword":"peculiar strange"},{"word":"rapid","level":2,"definition":"happening very quickly","example":"The rapid river moved so fast that logs were swept away in seconds.","imageKeyword":"rapid fast"},{"word":"reluctant","level":2,"definition":"slow to act because of doubt; unsure and holding back","example":"He was reluctant to jump in the pool because the water looked cold.","imageKeyword":"reluctant hesitant"},{"word":"sensitive","level":2,"definition":"easily hurt or upset","example":"His sensitive skin turned red when he stayed in the sun too long.","imageKeyword":"sensitive careful"},{"word":"severe","level":2,"definition":"very serious or very bad","example":"The severe storm brought strong winds that knocked down power lines.","imageKeyword":"severe storm"},{"word":"suitable","level":2,"definition":"right for a certain purpose","example":"Sneakers are suitable shoes for running but not for a fancy dinner.","imageKeyword":"suitable fitting"},{"word":"sufficient","level":2,"definition":"the right amount needed, not too little and not too much","example":"Make sure you have sufficient water for the whole hike.","imageKeyword":"enough sufficient"},{"word":"vacant","level":2,"definition":"empty and not being used, with no people or things inside","example":"The vacant house had no furniture and no people living in it.","imageKeyword":"vacant empty"},{"word":"vast","level":2,"definition":"extremely large and wide","example":"The vast ocean stretched as far as the eye could see.","imageKeyword":"vast ocean"},{"word":"vivid","level":2,"definition":"very bright and easy to picture in your mind","example":"She painted with vivid colors that made the flowers look real.","imageKeyword":"vivid colors"},{"word":"possess","level":2,"definition":"to have or own something as your own","example":"The old pirate was said to possess a chest full of gold coins.","imageKeyword":"possess own"},{"word":"reveal","level":2,"definition":"to show something that was hidden","example":"She pulled back the curtain to reveal the surprise behind it.","imageKeyword":"reveal show"},{"word":"assign","level":2,"definition":"to give someone a job or task to do","example":"The teacher will assign each student a different topic to research.","imageKeyword":"assign task"},{"word":"respond","level":2,"definition":"to answer or reply","example":"When the teacher asks a question, raise your hand to respond.","imageKeyword":"responding answer"},{"word":"require","level":2,"definition":"to need something before you can move forward","example":"This recipe requires three eggs and a cup of milk.","imageKeyword":"require need"},{"word":"oppose","level":2,"definition":"to be against something or disagree with it","example":"Some students opposed the new rule because they thought it was unfair.","imageKeyword":"oppose against"},{"word":"occupy","level":2,"definition":"to fill or use a space by being in it","example":"Boxes and old chairs occupy most of the space in the garage.","imageKeyword":"room filled with boxes"},{"word":"perform","level":2,"definition":"to do something in front of people","example":"The students will perform a play for their parents on Friday.","imageKeyword":"perform stage"},{"word":"accomplish","level":2,"definition":"to finish something well","example":"She accomplished her goal of reading fifty books in one year.","imageKeyword":"accomplish finish"},{"word":"cautious","level":2,"definition":"very careful so nothing bad happens","example":"The cautious girl looked both ways twice before crossing the street.","imageKeyword":"cautious careful"},{"word":"capable","level":2,"definition":"able to do something well","example":"He is capable of running a mile without stopping.","imageKeyword":"capable able"},{"word":"essential","level":2,"definition":"very important and needed","example":"Water is essential for all living things to survive.","imageKeyword":"essential important"},{"word":"fortunate","level":2,"definition":"having good things happen; lucky","example":"We were fortunate that the rain stopped just before our picnic.","imageKeyword":"fortunate lucky"},{"word":"incredible","level":2,"definition":"so great or very strong that it is hard to believe","example":"The magician did an incredible trick that made a dove appear from a hat.","imageKeyword":"incredible amazing"},{"word":"numerous","level":2,"definition":"very many, a large number of","example":"There were numerous stars in the sky that night, too many to count.","imageKeyword":"numerous many"},{"word":"positive","level":2,"definition":"sure something is true, or feeling hopeful","example":"She was positive she left her keys on the table because she saw them there.","imageKeyword":"child nodding yes"},{"word":"previous","level":2,"definition":"coming before in time or order","example":"In the previous chapter, the hero found a magic map.","imageKeyword":"previous before"},{"word":"region","level":2,"definition":"a large area of land","example":"The desert region gets very little rain all year.","imageKeyword":"region area"},{"word":"structure","level":2,"definition":"something that has been built, like a building or bridge","example":"The bridge is a strong structure made of steel and stone.","imageKeyword":"structure building"},{"word":"symbol","level":2,"definition":"a picture or mark that stands for something else","example":"A heart is a symbol that means love.","imageKeyword":"symbol heart"},{"word":"tradition","level":2,"definition":"something families or groups do the same way year after year","example":"We bake cookies every December—it is a family tradition.","imageKeyword":"tradition family"},{"word":"celebration","level":2,"definition":"a happy time when people come together","example":"The town held a celebration with fireworks when the team won.","imageKeyword":"celebration party"},{"word":"challenge","level":2,"definition":"something that is hard to do and tests your ability","example":"Climbing the mountain was a challenge, but they made it to the top.","imageKeyword":"challenge difficult"},{"word":"equipment","level":2,"definition":"tools or things you need to do a job","example":"The firefighter put on all her equipment before going into the building.","imageKeyword":"equipment tools"},{"word":"voyage","level":2,"definition":"a long trip, usually by sea","example":"The sailors went on a voyage across the ocean that lasted three months.","imageKeyword":"voyage ship"},{"word":"territory","level":2,"definition":"an area of land that belongs to someone","example":"The wolf marked its territory so other animals would stay away.","imageKeyword":"territory land"},{"word":"disaster","level":2,"definition":"a very bad event that causes great harm","example":"The flood was a disaster that damaged many homes in the town.","imageKeyword":"disaster flood"},{"word":"merely","level":2,"definition":"only, nothing more than","example":"She was merely trying to help, nothing more.","imageKeyword":"only just"},{"word":"precisely","level":2,"definition":"in an exact way, with no mistakes","example":"The code must follow the rules precisely, or the computer won't understand it.","imageKeyword":"exact precise"},{"word":"entirely","level":2,"definition":"completely, all the way","example":"The glass was entirely full, with no room for even one more drop.","imageKeyword":"completely full"},{"word":"scarcely","level":2,"definition":"almost not, hardly","example":"He could scarcely believe he won the spelling bee.","imageKeyword":"barely hardly"},{"word":"swiftly","level":2,"definition":"moving very quickly","example":"The deer swiftly ran through the forest and disappeared.","imageKeyword":"fast swift"},{"word":"willingly","level":2,"definition":"happy to do something without being forced","example":"He willingly shared his lunch with the new student.","imageKeyword":"willing happy"},{"word":"maintain","level":2,"definition":"to keep something in good shape","example":"You need to maintain your bike by keeping the tires full of air.","imageKeyword":"maintain care"},{"word":"establish","level":2,"definition":"to start or create something new","example":"The students established a recycling club at their school.","imageKeyword":"establish start"},{"word":"cooperate","level":2,"definition":"to work together with others","example":"The whole class had to cooperate to finish the mural on time.","imageKeyword":"cooperate teamwork"},{"word":"represent","level":2,"definition":"to stand for or speak for something","example":"The star on the flag represents the state we live in.","imageKeyword":"represent symbol"},{"word":"concentrate","level":2,"definition":"to think very hard about one thing","example":"It is hard to concentrate on homework when the TV is on.","imageKeyword":"concentrate focus"},{"word":"manufacture","level":2,"definition":"to make things in a factory, usually in large amounts","example":"The factory manufactures toys that are sold all over the world.","imageKeyword":"factory making"},{"word":"demonstrate","level":2,"definition":"to show how something works","example":"The teacher demonstrated how to mix paint colors on the paper.","imageKeyword":"demonstrate show"},{"word":"investigate","level":2,"definition":"to look into something to find out what really happened","example":"The detective investigated the missing cookies from the jar.","imageKeyword":"investigate search"},{"word":"discovery","level":2,"definition":"something new that you find or learn about for the first time","example":"We made a great discovery—a bird nest in our tree!","imageKeyword":"discovery find"},{"word":"penalty","level":2,"definition":"what happens when you break a rule","example":"The penalty for being late to class was missing five minutes of free time.","imageKeyword":"penalty punishment"},{"word":"quantity","level":2,"definition":"how much or how many of something there is","example":"She bought a large quantity of apples to make pies for the whole family.","imageKeyword":"quantity amount"},{"word":"reasonable","level":2,"definition":"fair and making good sense","example":"The price of the book was reasonable, so she had enough money to buy it.","imageKeyword":"reasonable fair"},{"word":"approach","level":2,"definition":"to come closer to something; also a way of dealing with a problem","example":"The cat quietly approached the bird, trying not to scare it.","imageKeyword":"approach near"},{"word":"collapse","level":2,"definition":"to fall down suddenly","example":"The tower of blocks collapsed when the baby bumped the table.","imageKeyword":"collapse falling"},{"word":"domestic","level":2,"definition":"relating to the home or one's own country; also raised by people, not wild","example":"Dogs and cats are domestic animals that live with people.","imageKeyword":"domestic pets"},{"word":"external","level":2,"definition":"on the outside of something, not inside","example":"The external walls of the house were painted bright yellow.","imageKeyword":"external outside"},{"word":"internal","level":2,"definition":"on the inside of something, not outside","example":"The doctor checked her internal organs to make sure she was healthy.","imageKeyword":"internal inside"},{"word":"annual","level":2,"definition":"happening once a year or relating to a one-year period","example":"The school's annual science fair is always in March.","imageKeyword":"calendar year circled"},{"word":"permission","level":2,"definition":"being allowed to do something by someone in charge","example":"You need permission from your parents before you go on the field trip.","imageKeyword":"permission allowed"},{"word":"recognize","level":2,"definition":"to know what something is because you have seen it before","example":"I didn't recognize him at first because he was wearing a costume.","imageKeyword":"recognize know"},{"word":"influence","level":2,"definition":"the power to change how someone thinks or acts","example":"Her older sister had a big influence on what music she liked.","imageKeyword":"influence effect"},{"word":"interpret","level":2,"definition":"to explain what something means","example":"She interpreted the French menu for her friends.","imageKeyword":"interpret meaning"},{"word":"adapt","level":2,"definition":"to change so you fit a new situation","example":"Animals adapt to new places by changing how they eat and sleep.","imageKeyword":"adapt change"},{"word":"benefit","level":2,"definition":"a good result or helpful thing you get","example":"One benefit of wearing a helmet is that it protects your head.","imageKeyword":"benefit help"},{"word":"durable","level":2,"definition":"strong and able to last a long time","example":"Her durable lunchbox did not crack even when it fell on the floor.","imageKeyword":"durable strong"},{"word":"genuine","level":2,"definition":"real and not fake","example":"His apology was genuine, so his friend forgave him.","imageKeyword":"genuine real"},{"word":"hesitate","level":2,"definition":"to pause because you are not sure","example":"She hesitated at the diving board, then took a deep breath and jumped.","imageKeyword":"hesitate pause"},{"word":"negotiate","level":2,"definition":"to talk to agree on a fair plan","example":"The sisters negotiated and chose to split the last cookie in half.","imageKeyword":"negotiate talk"},{"word":"temporary","level":2,"definition":"lasting only a short while, then going away","example":"The sign was temporary, so workers took it down after the road was fixed.","imageKeyword":"temporary short"},{"word":"reliable","level":2,"definition":"you can count on it to work or be true","example":"Our reliable bus driver came on time each day.","imageKeyword":"reliable trust"},{"word":"absorb","level":2,"definition":"to soak up a liquid","example":"The towel can absorb the water from the spilled juice.","imageKeyword":"absorb soak"},{"word":"attract","level":2,"definition":"to pull something toward you","example":"Bright flowers attract bees because the bees want nectar.","imageKeyword":"attract pull"},{"word":"predict","level":2,"definition":"to guess what will happen next","example":"Can you predict what will happen next in the story?","imageKeyword":"predict forecast"},{"word":"request","level":2,"definition":"to ask in a kind way for something","example":"She requested a book about sharks from the library.","imageKeyword":"request ask"},{"word":"reduce","level":2,"definition":"to make less; to lower the amount","example":"To reduce noise, the class spoke in whispers during the test.","imageKeyword":"reduce less"},{"word":"assemble","level":2,"definition":"to put parts together","example":"We assembled the puzzle pieces. The whole picture appeared.","imageKeyword":"assemble build"},{"word":"accumulate","level":2,"definition":"to gather more and more over time","example":"If you save a little each week, your money will accumulate quickly.","imageKeyword":"accumulate pile"},{"word":"acknowledge","level":2,"definition":"to show that you noticed or agree","example":"She nodded to acknowledge his question.","imageKeyword":"acknowledge nod"},{"word":"adequate","level":2,"definition":"enough to meet the need","example":"We had adequate food for the whole trip.","imageKeyword":"full water bottle"},{"word":"advocate","level":2,"definition":"to speak up for something you believe in","example":"He advocates for recycling at his school.","imageKeyword":"advocate support"},{"word":"allocate","level":2,"definition":"to set apart for a purpose","example":"She decided to allocate half her allowance to savings and half to spending.","imageKeyword":"allocate assign"},{"word":"ambiguous","level":2,"definition":"unclear because it could mean more than one thing","example":"The directions were ambiguous, so we got lost.","imageKeyword":"ambiguous confusing"},{"word":"amend","level":2,"definition":"to change something to fix or improve it","example":"He amended his essay after the teacher's comments.","imageKeyword":"amend edit"},{"word":"approximate","level":2,"definition":"close to the real number but not exact","example":"The approximate distance is ten miles.","imageKeyword":"approximate estimate"},{"word":"aspire","level":2,"definition":"to dream of doing something great","example":"She aspires to become a doctor one day.","imageKeyword":"aspire dream"},{"word":"assert","level":2,"definition":"to say something strongly and clearly","example":"He asserted that his answer was correct.","imageKeyword":"assert speak"},{"word":"authorize","level":2,"definition":"to give official permission for something","example":"The principal authorized the field trip.","imageKeyword":"authorize approve"},{"word":"beneficial","level":2,"definition":"helpful or good for you","example":"Eating fruit is beneficial for your health.","imageKeyword":"beneficial healthy"},{"word":"bias","level":2,"definition":"leaning toward one side instead of being fair to both","example":"A good judge should not show bias.","imageKeyword":"bias unfair"},{"word":"capacity","level":2,"definition":"the most that something can hold or carry","example":"The jar has a capacity of fifty marbles.","imageKeyword":"capacity full"},{"word":"clarify","level":2,"definition":"to say something again so it is clear","example":"Can you clarify what you mean? I do not understand the question.","imageKeyword":"magnifying glass text"},{"word":"coincide","level":2,"definition":"to happen at the same time as something else","example":"My birthday will coincide with the school carnival this year.","imageKeyword":"overlapping calendar events"},{"word":"commentary","level":2,"definition":"spoken or written opinions about an event","example":"The sports commentary made the game more exciting.","imageKeyword":"commentary sports"},{"word":"compensate","level":2,"definition":"to make up for something or pay someone back","example":"The store compensated her with a new toy after the broken one.","imageKeyword":"compensate repay"},{"word":"compile","level":2,"definition":"to put together facts from many places","example":"She compiled a list of her favorite songs.","imageKeyword":"compile list"},{"word":"complement","level":2,"definition":"something that goes well with another thing","example":"The red scarf was a nice complement to his coat.","imageKeyword":"complement match"},{"word":"comply","level":2,"definition":"to do what is asked or required","example":"Students must comply with the school rules.","imageKeyword":"comply follow"},{"word":"conceive","level":2,"definition":"to think of an idea","example":"She conceived a clever plan to surprise her friend.","imageKeyword":"conceive idea"},{"word":"confine","level":2,"definition":"to keep within limits","example":"The dog was confined to the backyard.","imageKeyword":"confine limit"},{"word":"consent","level":2,"definition":"saying yes; giving permission for something to happen","example":"You need your parents' consent to go on the trip.","imageKeyword":"consent permission"},{"word":"consequent","level":2,"definition":"happening as a result of something","example":"The heavy rain and the consequent flooding closed the road.","imageKeyword":"consequent result"},{"word":"consolidate","level":2,"definition":"to bring things together into one","example":"She consolidated her notes into one notebook.","imageKeyword":"consolidate combine"},{"word":"constraint","level":2,"definition":"a limit or rule that holds you back","example":"Time was a constraint, so we had to work fast.","imageKeyword":"constraint limit"},{"word":"consult","level":2,"definition":"to ask someone who knows a lot for help","example":"He consulted the librarian to find the right book.","imageKeyword":"consult advice"},{"word":"contemplate","level":2,"definition":"to think about something deeply","example":"She sat and contemplated what to write in her story.","imageKeyword":"contemplate think"},{"word":"contradict","level":2,"definition":"to say the opposite of what someone else said","example":"His actions contradicted his words.","imageKeyword":"contradict opposite"},{"word":"controversy","level":2,"definition":"a big argument among people about an important idea","example":"There was controversy over where to build the new park.","imageKeyword":"controversy debate"},{"word":"convene","level":2,"definition":"to come together for a meeting","example":"The club members convened in the library.","imageKeyword":"convene meeting"},{"word":"correspond","level":2,"definition":"to match or be alike to","example":"The answers correspond to the questions on the test.","imageKeyword":"correspond match"},{"word":"criteria","level":2,"definition":"rules used to judge or decide something","example":"The criteria for the art contest were neatness and color.","imageKeyword":"criteria checklist"},{"word":"currency","level":2,"definition":"the type of money a country uses","example":"The dollar is the currency of the United States.","imageKeyword":"currency money"},{"word":"deficiency","level":2,"definition":"a lack; when you have less of something than you need","example":"A deficiency of sunlight can make plants turn yellow.","imageKeyword":"deficiency lack"},{"word":"denote","level":2,"definition":"to be a sign of or to mean","example":"A red light denotes that you should stop.","imageKeyword":"denote sign"},{"word":"derive","level":2,"definition":"to get something from a place it comes from","example":"Many English words derive from Latin.","imageKeyword":"derive source"},{"word":"deviate","level":2,"definition":"to go a different way from what is usual","example":"He deviated from the trail and got lost.","imageKeyword":"deviate path"},{"word":"devote","level":2,"definition":"to give your time and effort to something","example":"He devoted the morning to practicing piano.","imageKeyword":"devote focus"},{"word":"diminish","level":2,"definition":"to become smaller or less","example":"The value of the old toy did not diminish—it actually went up over time.","imageKeyword":"diminish smaller"},{"word":"dispose","level":2,"definition":"to get rid of something","example":"Please dispose of the trash properly.","imageKeyword":"dispose trash"},{"word":"distort","level":2,"definition":"to twist out of shape","example":"The fun house mirror distorted her face.","imageKeyword":"distort mirror"},{"word":"diverse","level":2,"definition":"having many different kinds","example":"A diverse group of friends means you know people from many different places.","imageKeyword":"diverse variety"},{"word":"domain","level":2,"definition":"a specific area of knowledge, activity, or authority","example":"Science is her main domain of interest.","imageKeyword":"domain area"},{"word":"dominate","level":2,"definition":"to have the most power or control","example":"The tallest player dominated the game, scoring point after point.","imageKeyword":"dominate tower"},{"word":"draft","level":2,"definition":"a first try of something written","example":"He wrote a rough draft of his story.","imageKeyword":"draft writing"},{"word":"duration","level":2,"definition":"how long something lasts","example":"The duration of the movie was two hours.","imageKeyword":"duration time"},{"word":"empirical","level":2,"definition":"based on what you watch and see and test","example":"The scientist gathered empirical data by observing the plants every day.","imageKeyword":"empirical experiment"},{"word":"enforce","level":2,"definition":"to make sure a rule is followed","example":"The teacher enforced the no-running rule in the hallway.","imageKeyword":"enforce rule"},{"word":"entity","level":2,"definition":"a single thing that has its own name and life","example":"A country, a school, and a person are each a separate entity.","imageKeyword":"entity thing"},{"word":"equate","level":2,"definition":"to think of two things as equal","example":"You should not equate being quiet with being shy.","imageKeyword":"equate equal"},{"word":"erode","level":2,"definition":"to slowly wear away","example":"The waves eroded the cliff over many years.","imageKeyword":"erode cliff"},{"word":"exceed","level":2,"definition":"to go beyond a limit or amount","example":"His test score exceeded the class average.","imageKeyword":"exceed beyond"},{"word":"explicit","level":2,"definition":"said clearly so there is no mistake about what you mean","example":"The teacher gave explicit instructions for the project.","imageKeyword":"explicit clear"},{"word":"extract","level":2,"definition":"to pull out or take away","example":"The dentist extracted the loose tooth.","imageKeyword":"extract pull"},{"word":"facilitate","level":2,"definition":"to help something happen","example":"The ramp facilitates entry for people in wheelchairs.","imageKeyword":"facilitate help"},{"word":"finite","level":2,"definition":"having a limit or end","example":"We have a finite amount of time before lunch.","imageKeyword":"finite limited"},{"word":"fluctuate","level":2,"definition":"to go up and down or change often","example":"The temperature fluctuates a lot in spring, warm one day and cold the next.","imageKeyword":"fluctuate change"},{"word":"format","level":2,"definition":"the way something is set up or arranged","example":"The report was written in a clear format.","imageKeyword":"format layout"},{"word":"formula","level":2,"definition":"a rule or way written with symbols","example":"She used a math formula to solve the problem.","imageKeyword":"formula math"},{"word":"foundation","level":2,"definition":"the base that holds something up","example":"The house was built on a strong foundation.","imageKeyword":"foundation base"},{"word":"framework","level":2,"definition":"a basic frame or shape that holds things up that supports or organizes something","example":"The framework of the building was made of steel.","imageKeyword":"framework structure"},{"word":"furthermore","level":2,"definition":"in addition to what was already said","example":"The book is fun; furthermore, it teaches great lessons.","imageKeyword":"furthermore also"},{"word":"generate","level":2,"definition":"to create or produce","example":"The AI can generate a realistic painting from just a short text description.","imageKeyword":"generate create"},{"word":"guideline","level":2,"definition":"a rule that tells you how to do something","example":"Follow the guidelines to stay safe.","imageKeyword":"guideline rules"},{"word":"hence","level":2,"definition":"as a result of what was just said; therefore","example":"It rained all day; hence, the game was canceled.","imageKeyword":"hence therefore"},{"word":"hierarchy","level":2,"definition":"a system where things go from top to bottom","example":"In the school, there is a clear hierarchy from principal to teacher to student.","imageKeyword":"hierarchy pyramid"},{"word":"hypothesis","level":2,"definition":"a guess about what will happen in a test","example":"His hypothesis was that plants grow faster with more sunlight.","imageKeyword":"hypothesis science"},{"word":"identical","level":2,"definition":"exactly the same","example":"The twins wore identical outfits.","imageKeyword":"identical same"},{"word":"ideology","level":2,"definition":"a set of political or social beliefs held by a group","example":"The team's ideology was simple: practice hard, play fair, and never give up.","imageKeyword":"ideology beliefs"},{"word":"implication","level":2,"definition":"a meaning that is suggested but not said directly","example":"The implication of his smile was that he had good news.","imageKeyword":"implication hint"},{"word":"impose","level":2,"definition":"to force a rule or task on someone","example":"The school imposed a new dress code.","imageKeyword":"impose force"},{"word":"incentive","level":2,"definition":"something that makes you want to try harder","example":"Getting a sticker was a great incentive to do homework.","imageKeyword":"incentive reward"},{"word":"incorporate","level":2,"definition":"to include as part of something","example":"She incorporated art into her book report.","imageKeyword":"incorporate include"},{"word":"index","level":2,"definition":"a list at the back of a book that helps you find things","example":"He looked in the index to find the chapter on volcanoes.","imageKeyword":"index book"},{"word":"induce","level":2,"definition":"to cause or lead something to happen","example":"The warm sunshine induced the flowers to bloom.","imageKeyword":"induce cause"},{"word":"inherent","level":2,"definition":"a natural part of something","example":"Curiosity is inherent in children—they are born wanting to explore.","imageKeyword":"inherent natural"},{"word":"inhibit","level":2,"definition":"to hold back or prevent","example":"Fear can inhibit you from trying new things.","imageKeyword":"inhibit block"},{"word":"initiate","level":2,"definition":"to start or begin something new","example":"She initiated a recycling club at school.","imageKeyword":"initiate start"},{"word":"innovation","level":2,"definition":"a new idea or way of doing things","example":"The innovation of smartphones changed how we talk.","imageKeyword":"innovation invention"},{"word":"insert","level":2,"definition":"to put something inside","example":"He inserted the coin into the machine.","imageKeyword":"insert coin"},{"word":"integral","level":2,"definition":"very important and needed as part of something","example":"Teamwork is an integral part of winning the game.","imageKeyword":"integral important"},{"word":"intervene","level":2,"definition":"to step in to help or stop something","example":"The teacher intervened before the argument got worse.","imageKeyword":"intervene help"},{"word":"invoke","level":2,"definition":"to call upon for help or use","example":"He invoked the rules to settle the disagreement.","imageKeyword":"invoke call"},{"word":"isolate","level":2,"definition":"to keep apart from others","example":"The sick student was isolated, so others would not catch the cold.","imageKeyword":"isolate separate"},{"word":"levy","level":2,"definition":"to officially impose a tax or fee","example":"The town voted to levy a small tax for the new library.","imageKeyword":"levy tax"},{"word":"liberal","level":2,"definition":"giving freely and in large amounts; generous","example":"She took a liberal amount of paint for her project.","imageKeyword":"liberal generous"},{"word":"likewise","level":2,"definition":"in the same way","example":"She smiled, and he did likewise.","imageKeyword":"likewise same"},{"word":"magnitude","level":2,"definition":"the size or importance of something","example":"The magnitude of the earthquake surprised all.","imageKeyword":"magnitude size"},{"word":"manifest","level":2,"definition":"to show or make clear","example":"Her talent manifested clearly in every painting she made.","imageKeyword":"manifest show"}];